import{_ as a,c as s,o as i,a4 as e}from"./chunks/framework.BmdFiWrL.js";const b=JSON.parse('{"title":"如何启用 TSDB","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"guide/q15.md","filePath":"guide/q15.md","lastUpdated":1779120648000}'),t={name:"guide/q15.md"},n=e(`<h1 id="如何启用-tsdb" tabindex="-1">如何启用 TSDB <a class="header-anchor" href="#如何启用-tsdb" aria-label="Permalink to &quot;如何启用 TSDB&quot;">​</a></h1><p>TSDB 默认关闭。Dashboard 只有在配置了 <code>tsdb.data_path</code> 后才会初始化内置的 VictoriaMetrics 存储。</p><h2 id="适用范围" tabindex="-1">适用范围 <a class="header-anchor" href="#适用范围" aria-label="Permalink to &quot;适用范围&quot;">​</a></h2><p>启用 TSDB 后，服务器详情页的历史指标图表可以查询 1 天、7 天、30 天等历史周期；未启用时，前端会锁定这些历史周期。</p><p>服务监控历史在未启用 TSDB 时仍会从数据库读取；启用后会改为从 TSDB 查询。</p><h2 id="配置方式" tabindex="-1">配置方式 <a class="header-anchor" href="#配置方式" aria-label="Permalink to &quot;配置方式&quot;">​</a></h2><p>编辑 Dashboard 配置文件，通常是 <code>/opt/nezha/dashboard/data/config.yaml</code>，增加或修改：</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">tsdb</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  data_path</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;data/tsdb&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  retention_days</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">30</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  min_free_disk_space_gb</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  max_memory_mb</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">256</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  write_buffer_size</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">512</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  write_buffer_flush_interval</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">5</span></span></code></pre></div><p><code>data_path</code> 可以填写相对路径或绝对路径。相对路径会按 Dashboard 运行目录解析。此项为空时 TSDB 不会启用。</p><p>也可以使用环境变量启用：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">NZ_TSDB_DATA_PATH</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">data/tsdb</span></span></code></pre></div><p>修改配置后需要重启 Dashboard。</p><h2 id="如何确认已启用" tabindex="-1">如何确认已启用 <a class="header-anchor" href="#如何确认已启用" aria-label="Permalink to &quot;如何确认已启用&quot;">​</a></h2><p>重启后查看 Dashboard 日志：</p><ul><li>出现 <code>TSDB initialized successfully</code>：TSDB 已启用。</li><li>出现 <code>TSDB is disabled (tsdb.data_path not configured)</code>：未配置 <code>data_path</code>，TSDB 仍关闭。</li></ul><p>前端也会通过系统配置接口读取 <code>tsdb_enabled</code>。如果该值为 <code>false</code>，服务器详情页的历史指标周期会保持锁定。</p><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to &quot;注意事项&quot;">​</a></h2><p>启用 TSDB 后，Dashboard 会删除旧的 <code>service_histories</code> 数据库表，已有服务监控历史不会自动迁移到 TSDB。建议在启用前先备份数据库。</p><p>TSDB 使用本地磁盘存储，请确保 <code>data_path</code> 所在分区有足够空间，并根据保留天数和服务器数量调整 <code>retention_days</code>、<code>min_free_disk_space_gb</code> 和 <code>max_memory_mb</code>。</p>`,19),d=[n];function h(l,p,o,r,c,k){return i(),s("div",null,d)}const g=a(t,[["render",h]]);export{b as __pageData,g as default};
